const babelTypes = require('@babel/types');

const {
  IMPORT_TYPES,
  ISLAND_WRAPPER,
  NORDIC_ISLAND_ENTRYPOINT,
} = require('../../../constants/islands');
const {
  addComponentToDestinationIfValid,
  getComponentTypeByPath,
} = require('../../../helpers/islands/component');
const {
  getScriptFullPathWithExtension,
} = require('../../../helpers/file/path-detail');
const { isImportType } = require('../../../helpers/babel/typescript');

/**
 * @param {{ source: babelTypes.StringLiteral, specifiers: (babelTypes.ImportDefaultSpecifier | babelTypes.ImportNamespaceSpecifier | babelTypes.ImportSpecifier)[], isType: boolean }} nodeData
 * @param {string} dir
 * @returns {{ appComponentsUsage: import('../../../helpers/islands/component').ComponentManifest, islandWrapperUsage: string? }}
 */
const getImportDeclarationUsage = ({ source, specifiers, isType }, dir) => {
  const appComponentsUsage = {};
  const importType = getComponentTypeByPath(source.value);

  let islandWrapperUsage = null;

  if (!specifiers.length || !importType || isType) {
    return {
      appComponentsUsage,
      islandWrapperUsage,
    };
  }

  /** @type {import('../../../helpers/islands/component').PotencialComponent} */
  const component = {
    importName: null,
    path:
      importType === IMPORT_TYPES.RELATIVE ||
      importType === IMPORT_TYPES.NORDIC_ALIAS ||
      importType === IMPORT_TYPES.NODE_SUBPATH
        ? getScriptFullPathWithExtension(source.value, dir)
        : NORDIC_ISLAND_ENTRYPOINT,
    namedExport: false,
  };

  specifiers.forEach((specifier) => {
    // import { type ComponentType } from '../types/component-type';
    if (isImportType(specifier)) {
      return;
    }

    // example 1: import * as MyComponent from './ui-components/my-component';
    // example 2: import MyComponent from './ui-components/my-component';
    // example 3: import { MyComponent: Component } from './ui-components/my-component';
    // example 4: import { MyComponent, MyComponent2 } from './ui-components/my-component';
    // example 5: import { default as MyComponent2 } from './ui-components/my-component';
    const localName = specifier.local.name;

    component.importName =
      babelTypes.isImportSpecifier(specifier) &&
      babelTypes.isIdentifier(specifier.imported)
        ? specifier.imported.name
        : IMPORT_TYPES.DEFAULT;
    component.namedExport =
      babelTypes.isImportSpecifier(specifier) &&
      babelTypes.isIdentifier(specifier.imported) &&
      specifier.imported.name !== IMPORT_TYPES.DEFAULT;

    if (importType === IMPORT_TYPES.NORDIC_ISLAND) {
      if (!component.namedExport || component.importName === ISLAND_WRAPPER) {
        islandWrapperUsage = localName;
      }

      return;
    }

    if (
      importType !== IMPORT_TYPES.RELATIVE &&
      importType !== IMPORT_TYPES.NORDIC_ALIAS &&
      importType !== IMPORT_TYPES.NODE_SUBPATH
    ) {
      return;
    }

    addComponentToDestinationIfValid(appComponentsUsage, {
      localName,
      component: { ...component },
    });
  });

  return {
    appComponentsUsage,
    islandWrapperUsage,
  };
};

module.exports = {
  getImportDeclarationUsage,
};
